using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

Console.WriteLine("Research Agent Starting...");

// Configure the AI client with tool support
var openAiClient = new OpenAIClient(
    Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "your-api-key");

IChatClient chatClient = openAiClient
    .GetChatClient("gpt-4o")
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Initialize the notebook for the note-taking tool
var notebook = new ResearchNotebook();

// Define the tools available to the agent
var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(
            (string query) => WebSearchTool.SearchAsync(query),
            "web_search",
            "Searches the web for information on a given query and returns relevant results."),
        AIFunctionFactory.Create(
            ([Description("The title or heading for this note")] string title,
             [Description("The content of the note to save")] string content) =>
                notebook.AddNote(title, content),
            "take_note",
            "Saves a note with a title and content to the research notebook for later summarization."),
        AIFunctionFactory.Create(
            () => notebook.GetAllNotes(),
            "get_notes",
            "Retrieves all notes currently saved in the research notebook.")
    ]
};

// Get the research topic from the user
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Run the agent loop
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research the given topic thoroughly by:
        1. Searching the web for relevant information (perform multiple searches to cover different aspects)
        2. Taking notes on key findings as you discover them
        3. After gathering enough information, reviewing your notes and providing a comprehensive summary

        Always take notes on important findings before moving to the next search.
        When you have enough information, provide a final summary to the user.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
};

var response = await chatClient.GetResponseAsync(messages, chatOptions);
Console.WriteLine("\n=== Research Summary ===\n");
Console.WriteLine(response.Text);

// Display collected notes
var notes = notebook.GetAllNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n=== Research Notes ===\n");
    foreach (var note in notes)
    {
        Console.WriteLine($"## {note.Title}");
        Console.WriteLine(note.Content);
        Console.WriteLine();
    }
}

// --- Tool Implementations ---

/// <summary>Simulates web search results for demonstration purposes.</summary>
static class WebSearchTool
{
    public static Task<string> SearchAsync(string query)
    {
        // In production, this would call a real search API (Bing, Google, etc.)
        var results = new[]
        {
            new { Title = $"Overview of {query}", Snippet = $"Comprehensive overview covering the main aspects of {query}. This topic encompasses multiple areas of study and has significant real-world applications.", Url = $"https://example.com/overview/{Uri.EscapeDataString(query)}" },
            new { Title = $"Recent developments in {query}", Snippet = $"Latest research and developments related to {query} show promising advances in the field, with new breakthroughs reported in 2025.", Url = $"https://example.com/recent/{Uri.EscapeDataString(query)}" },
            new { Title = $"{query} - Key concepts and applications", Snippet = $"The key concepts behind {query} include foundational principles that drive innovation. Applications range from industry to academia.", Url = $"https://example.com/concepts/{Uri.EscapeDataString(query)}" }
        };

        var json = JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        return Task.FromResult(json);
    }
}

/// <summary>Stores research notes collected by the agent.</summary>
class ResearchNotebook
{
    private readonly List<Note> _notes = [];

    public string AddNote(string title, string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note saved: '{title}'";
    }

    public List<Note> GetAllNotes() => [.. _notes];
}

record Note(string Title, string Content, DateTime Timestamp);

